#ifndef _SOFA_PBRPC_COMPRESSION_COMPRESSED_STREAM_H_
#define _SOFA_PBRPC_COMPRESSION_COMPRESSED_STREAM_H_

#include <google/protobuf/io/zero_copy_stream.h>

